namespace sv_e6277786bb234e2e88355c629b29b05f.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

namespace sv_e6277786bb234e2e88355c629b29b05f.Services;

public class MockChatService : IChatService
{
    private readonly List<Channel> _channels;
    private readonly List<Message> _messages;
    private int _nextMessageId = 100;

    public MockChatService()
    {
        _channels = new()
        {
            new(1, "general", "General discussion and announcements", 3),
            new(2, "engineering", "Engineering team discussions", 0),
            new(3, "design", "Design team and UI/UX discussions", 7),
            new(4, "random", "Off-topic conversations and fun", 1),
        };

        var now = DateTime.UtcNow;
        _messages = new()
        {
            // #general
            new(1, 1, "Alice", "Hey team! Welcome to the new chat platform 🎉", now.AddHours(-5), null,
                new() { new("🎉", new() { "Bob", "Carol" }), new("👋", new() { "Dave" }) }),
            new(2, 1, "Bob", "Looks great! Really liking the new interface.", now.AddHours(-4.5), null,
                new() { new("👍", new() { "Alice" }) }),
            new(3, 1, "Carol", "Thanks for setting this up!", now.AddHours(-4), null, new()),
            new(4, 1, "Dave", "When is the next team sync?", now.AddHours(-3), null, new()),
            new(5, 1, "Alice", "Tomorrow at 10am. I'll send a calendar invite.", now.AddHours(-2.5), null,
                new() { new("👍", new() { "Dave", "Bob" }) }),
            new(6, 1, "Bob", "Has anyone reviewed the new PR for the auth module?", now.AddHours(-2), null, new()),
            new(7, 1, "Carol", "I'll take a look this afternoon.", now.AddHours(-1.5), null, new()),
            new(8, 1, "Dave", "Don't forget to update your time entries for this week.", now.AddHours(-1), null,
                new() { new("✅", new() { "Alice", "Carol" }) }),
            new(9, 1, "Alice", "Just pushed the latest docs update. Please review when you get a chance.", now.AddMinutes(-30), null, new()),
            new(10, 1, "Bob", "On it! Also, the CI pipeline needs some attention.", now.AddMinutes(-15), null, new()),
            new(11, 1, "Carol", "Good morning everyone! ☀️", now.AddMinutes(-5), null, new()),
            new(12, 1, "Dave", "Morning! Ready for a productive day.", now.AddMinutes(-2), null,
                new() { new("☀️", new() { "Carol" }) }),

            // Thread replies for message 6 (Bob's PR question)
            new(13, 1, "Alice", "I started reviewing it yesterday. Found a couple of issues with the token validation.", now.AddHours(-1.8), 6, new()),
            new(14, 1, "Dave", "The error handling in the refresh flow needs some work too.", now.AddHours(-1.6), 6, new()),
            new(15, 1, "Bob", "Thanks! I'll address those comments today.", now.AddHours(-1.4), 6, new()),

            // Thread replies for message 1 (welcome message)
            new(16, 1, "Eve", "Happy to be here!", now.AddHours(-4.5), 1, new()),
            new(17, 1, "Frank", "This is awesome! Great work on the setup.", now.AddHours(-4.2), 1, new()),

            // #engineering
            new(20, 2, "Alice", "New deployment pipeline is ready for testing.", now.AddHours(-3), null,
                new() { new("🚀", new() { "Bob", "Dave" }) }),
            new(21, 2, "Dave", "I'll run the integration tests this afternoon.", now.AddHours(-2), null, new()),
            new(22, 2, "Bob", "Found a bug in the caching layer. Creating a ticket now.", now.AddHours(-1), null,
                new() { new("🐛", new() { "Alice" }) }),
            new(23, 2, "Alice", "Let's discuss the architecture for the new microservice.", now.AddMinutes(-20), null, new()),
            new(24, 2, "Dave", "I've drafted an RFC. Check your email for the link.", now.AddMinutes(-10), null,
                new() { new("👀", new() { "Alice", "Bob" }) }),

            // Thread replies for message 20
            new(25, 2, "Carol", "The staging deploy worked perfectly. Ready for prod.", now.AddHours(-2.5), 20, new()),
            new(26, 2, "Bob", "Let's schedule the prod deploy for tomorrow.", now.AddHours(-2.2), 20, new()),

            // #design
            new(30, 3, "Carol", "New mockups for the dashboard are ready for review.", now.AddHours(-6), null,
                new() { new("😍", new() { "Alice", "Eve" }), new("🎨", new() { "Frank" }) }),
            new(31, 3, "Eve", "Love the color palette! The contrast ratios look solid.", now.AddHours(-5), null, new()),
            new(32, 3, "Frank", "Can we adjust the spacing on the sidebar? Feels a bit tight.", now.AddHours(-4), null, new()),
            new(33, 3, "Carol", "Sure, I'll update the specs and share a revised version.", now.AddHours(-3), null, new()),
            new(34, 3, "Eve", "The new icon set looks fantastic. Very cohesive.", now.AddMinutes(-45), null,
                new() { new("👍", new() { "Carol", "Frank" }) }),

            // #random
            new(40, 4, "Bob", "Anyone up for lunch today? 🍕", now.AddHours(-3), null,
                new() { new("🍕", new() { "Dave", "Carol" }) }),
            new(41, 4, "Dave", "Pizza sounds good! Let's meet at noon.", now.AddHours(-2.5), null, new()),
            new(42, 4, "Carol", "I'm in! See you all downstairs.", now.AddHours(-2), null, new()),
            new(43, 4, "Frank", "Check out this article on Blazor performance tips — really insightful.", now.AddMinutes(-30), null, new()),
        };
    }

    public Task<List<Channel>> GetChannelsAsync()
        => Task.FromResult(_channels.Select(c => c with { }).ToList());

    public Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take)
    {
        // Returns root messages (not thread replies) in chronological order.
        // skip=0 returns the most recent 'take' messages.
        var rootMessages = _messages
            .Where(m => m.ChannelId == channelId && m.ReplyToId == null)
            .OrderByDescending(m => m.SentAt)
            .Skip(skip)
            .Take(take)
            .OrderBy(m => m.SentAt)
            .ToList();

        return Task.FromResult(rootMessages);
    }

    public Task<Message> SendMessageAsync(int channelId, string content, int? replyToId)
    {
        var msg = new Message(
            Interlocked.Increment(ref _nextMessageId),
            channelId,
            "You",
            content,
            DateTime.UtcNow,
            replyToId,
            new List<Reaction>()
        );
        _messages.Add(msg);
        return Task.FromResult(msg);
    }

    public Task<List<Message>> GetThreadAsync(int rootMessageId)
    {
        var replies = _messages
            .Where(m => m.ReplyToId == rootMessageId)
            .OrderBy(m => m.SentAt)
            .ToList();
        return Task.FromResult(replies);
    }

    public Task AddReactionAsync(int messageId, string emoji)
    {
        var msg = _messages.FirstOrDefault(m => m.Id == messageId);
        if (msg != null)
        {
            var reaction = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
            if (reaction != null)
            {
                if (!reaction.Users.Contains("You"))
                    reaction.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(emoji, new List<string> { "You" }));
            }
        }
        return Task.CompletedTask;
    }

    public Task MarkChannelReadAsync(int channelId)
    {
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        return Task.CompletedTask;
    }
}

const observers = {};

export function scrollToBottom(element) {
    if (element) {
        element.scrollTop = element.scrollHeight;
    }
}

export function observeScrollTop(id, dotNetRef, sentinel) {
    if (observers[id]) observers[id].disconnect();

    const root = sentinel.closest('.message-list') || sentinel.parentElement;
    const observer = new IntersectionObserver((entries) => {
        if (entries[0].isIntersecting) {
            dotNetRef.invokeMethodAsync('OnScrolledToTop');
        }
    }, { root: root, threshold: 0.1 });

    observer.observe(sentinel);
    observers[id] = observer;
}

export function dispose(id) {
    if (observers[id]) {
        observers[id].disconnect();
        delete observers[id];
    }
}

/* ===== Chat Layout ===== */
.chat-container {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    background: #fff;
}

/* ===== Channel Sidebar ===== */
.channel-sidebar {
    width: 260px;
    min-width: 260px;
    background: #1a1d21;
    color: #ccc;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #333;
}

.sidebar-header {
    padding: 16px 16px 12px;
    border-bottom: 1px solid #333;
}

.sidebar-header h2 {
    margin: 0;
    font-size: 1.1rem;
    color: #fff;
    font-weight: 700;
}

.sidebar-label {
    padding: 12px 16px 4px;
    font-size: 0.75rem;
    text-transform: uppercase;
    font-weight: 700;
    color: #999;
    letter-spacing: 0.05em;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding-bottom: 8px;
}

.channel-item {
    padding: 5px 16px;
    cursor: pointer;
    display: flex;
    align-items: center;
    gap: 8px;
    transition: background 0.15s;
    border-radius: 6px;
    margin: 1px 8px;
}

.channel-item:hover {
    background: #2c2f33;
}

.channel-item.active {
    background: #1164a3;
    color: #fff;
}

.channel-info {
    flex: 1;
    min-width: 0;
}

.channel-name {
    font-size: 0.9rem;
    font-weight: 500;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.channel-item.active .channel-name {
    font-weight: 700;
    color: #fff;
}

.channel-desc {
    font-size: 0.72rem;
    color: #999;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    margin-top: 1px;
}

.channel-item.active .channel-desc {
    color: rgba(255, 255, 255, 0.7);
}

.unread-badge {
    font-size: 0.7rem;
    min-width: 20px;
    text-align: center;
    border-radius: 10px;
    padding: 1px 6px;
    background: #e74c3c;
    color: #fff;
    font-weight: 700;
    flex-shrink: 0;
}

/* ===== Main Area ===== */
.main-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    background: #fff;
    min-width: 0;
}

.channel-header {
    padding: 10px 20px;
    border-bottom: 1px solid #e0e0e0;
    background: #fff;
    flex-shrink: 0;
}

.channel-header h3 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: #1a1d21;
}

.channel-header p {
    margin: 2px 0 0;
    font-size: 0.82rem;
    color: #666;
}

.no-channel-selected {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #888;
    font-size: 1.1rem;
}

/* ===== Message List ===== */
.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.scroll-sentinel {
    height: 1px;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    color: #888;
    font-size: 0.85rem;
}

/* ===== Message Item ===== */
.message-item {
    padding: 6px 20px;
    position: relative;
    transition: background 0.1s;
}

.message-item:hover,
.message-item.hovered {
    background: #f8f8f8;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 1px;
