toolArgs.file_text:
/* ===== Chat Layout ===== */
.chat-container {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    background: #fff;
}

/* ===== Channel Sidebar ===== */
.channel-sidebar {
    width: 260px;
    min-width: 260px;
    background: #1a1d21;
    color: #ccc;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #333;
}

.sidebar-header {
    padding: 16px 16px 12px;
    border-bottom: 1px solid #333;
}

.sidebar-header h2 {
    margin: 0;
    font-size: 1.1rem;
    color: #fff;
    font-weight: 700;
}

.sidebar-label {
    padding: 12px 16px 4px;
    font-size: 0.75rem;
    text-transform: uppercase;
    font-weight: 700;
    color: #999;
    letter-spacing: 0.05em;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding-bottom: 8px;
}

.channel-item {
    padding: 5px 16px;
    cursor: pointer;
    display: flex;
    align-items: center;
    gap: 8px;
    transition: background 0.15s;
    border-radius: 6px;
    margin: 1px 8px;
}

.channel-item:hover {
    background: #2c2f33;
}

.channel-item.active {
    background: #1164a3;
    color: #fff;
}

.channel-info {
    flex: 1;
    min-width: 0;
}

.channel-name {
    font-size: 0.9rem;
    font-weight: 500;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.channel-item.active .channel-name {
    font-weight: 700;
    color: #fff;
}

.channel-desc {
    font-size: 0.72rem;
    color: #999;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    margin-top: 1px;
}

.channel-item.active .channel-desc {
    color: rgba(255, 255, 255, 0.7);
}

.unread-badge {
    font-size: 0.7rem;
    min-width: 20px;
    text-align: center;
    border-radius: 10px;
    padding: 1px 6px;
    background: #e74c3c;
    color: #fff;
    font-weight: 700;
    flex-shrink: 0;
}

/* ===== Main Area ===== */
.main-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    background: #fff;
    min-width: 0;
}

.channel-header {
    padding: 10px 20px;
    border-bottom: 1px solid #e0e0e0;
    background: #fff;
    flex-shrink: 0;
}

.channel-header h3 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: #1a1d21;
}

.channel-header p {
    margin: 2px 0 0;
    font-size: 0.82rem;
    color: #666;
}

.no-channel-selected {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #888;
    font-size: 1.1rem;
}

/* ===== Message List ===== */
.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.scroll-sentinel {
    height: 1px;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    color: #888;
    font-size: 0.85rem;
}

/* ===== Message Item ===== */
.message-item {
    padding: 6px 20px;
    position: relative;
    transition: background 0.1s;
}

.message-item:hover,
.message-item.hovered {
    background: #f8f8f8;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 1px;
}

.message-author {
    font-weight: 700;
    font-size: 0.9rem;
    color: #1a1d21;
}

.message-time {
    font-size: 0.75rem;
    color: #999;
}

.message-content {
    font-size: 0.9rem;
    line-height: 1.46;
    color: #1a1d21;
    word-wrap: break-word;
}

/* ===== Reactions ===== */
.message-reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    padding: 2px 8px;
    background: #f0f4ff;
    border: 1px solid #d0d8e8;
    border-radius: 12px;
    font-size: 0.8rem;
    cursor: default;
    transition: background 0.15s;
}

.reaction-badge:hover {
    background: #dde6ff;
    border-color: #a8b8d8;
}

/* ===== Thread Link ===== */
.thread-link {
    background: none;
    border: none;
    color: #1264a3;
    font-size: 0.8rem;
    cursor: pointer;
    padding: 4px 0 0;
    font-weight: 600;
    display: inline-block;
}

.thread-link:hover {
    text-decoration: underline;
}

/* ===== Message Actions (hover toolbar) ===== */
.message-actions {
    position: absolute;
    top: -8px;
    right: 20px;
    display: flex;
    gap: 1px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
    z-index: 5;
}

.action-btn {
    background: none;
    border: none;
    cursor: pointer;
    padding: 3px 7px;
    border-radius: 4px;
    font-size: 0.85rem;
    transition: background 0.15s;
    line-height: 1;
}

.action-btn:hover {
    background: #f0f0f0;
}

/* ===== Emoji Picker ===== */
.emoji-picker {
    position: absolute;
    right: 20px;
    top: -44px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    padding: 4px 6px;
    display: flex;
    gap: 2px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
    z-index: 10;
}

.emoji-btn {
    background: none;
    border: none;
    cursor: pointer;
    padding: 4px 5px;
    border-radius: 4px;
    font-size: 1.1rem;
    transition: background 0.15s;
    line-height: 1;
}

.emoji-btn:hover {
    background: #f0f0f0;
}

/* ===== Message Input ===== */
.message-input {
    padding: 10px 20px 14px;
    border-top: 1px solid #e0e0e0;
    display: flex;
    gap: 8px;
    align-items: flex-end;
    background: #fff;
    flex-shrink: 0;
}

.message-input textarea {
    flex: 1;
    border: 1px solid #ccc;
    border-radius: 8px;
    padding: 8px 12px;
    resize: none;
    font-size: 0.9rem;
    font-family: inherit;
    outline: none;
    min-height: 38px;
    max-height: 120px;
    line-height: 1.4;
}

.message-input textarea:focus {
    border-color: #1264a3;
    box-shadow: 0 0 0 1px #1264a3;
}

.message-input .btn {
    border-radius: 8px;
    padding: 7px 16px;
    font-weight: 600;
    font-size: 0.85rem;
    white-space: nowrap;
}

/* ===== Thread Panel ===== */
.thread-panel {
    width: 380px;
    min-width: 380px;
    border-left: 1px solid #e0e0e0;
    display: flex;
    flex-direction: column;
    background: #fff;
}

.thread-header {
    padding: 10px 16px;
    border-bottom: 1px solid #e0e0e0;
    display: flex;
    align-items: center;
    justify-content: space-between;
    flex-shrink: 0;
}

.thread-header h4 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
}

.thread-close-btn {
    background: none;
    border: none;
    cursor: pointer;
    font-size: 1.2rem;
    color: #666;
    padding: 2px 6px;
    border-radius: 4px;
    line-height: 1;
}

.thread-close-btn:hover {
    background: #f0f0f0;
    color: #333;
}

.thread-root-message {
    padding: 12px 16px;
    background: #fafafa;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.thread-divider {
    padding: 8px 16px;
    font-size: 0.78rem;
    color: #888;
    border-bottom: 1px solid #eee;
    text-align: center;
    font-weight: 600;
    flex-shrink: 0;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 4px 0;
}

.thread-replies .message-item {
    padding: 6px 16px;
}

