@using sv_e6277786bb234e2e88355c629b29b05f.Services

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h2>💬 Messenger</h2>
    </div>
    <div class="sidebar-label">Channels</div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == SelectedChannelId"
                         OnSelected="() => OnChannelSelected.InvokeAsync(channel.Id)" />
        }
    </div>
</div>

@code {
    [Parameter] public List<Channel> Channels { get; set; } = new();
    [Parameter] public int? SelectedChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

@using sv_e6277786bb234e2e88355c629b29b05f.Services
@implements IAsyncDisposable

<div class="message-list" @ref="scrollContainer">
    <div @ref="topSentinel" class="scroll-sentinel">
        @if (IsLoadingMore)
        {
            <div class="loading-indicator">Loading older messages…</div>
        }
    </div>

    @foreach (var message in Messages)
    {
        <MessageItem Message="message"
                     ReplyCount="GetReplyCount(message.Id)"
                     OnOpenThread="OnOpenThread"
                     OnReact="OnReact" />
    }
</div>

@code {
    [Inject] private IJSRuntime JS { get; set; } = default!;

    [Parameter] public List<Message> Messages { get; set; } = new();
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = new();
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private ElementReference scrollContainer;
    private ElementReference topSentinel;
    private IJSObjectReference? jsModule;
    private DotNetObjectReference<MessageList>? dotNetRef;

    // Tracks whether we should auto-scroll to the bottom after render.
    private bool scrollToBottomOnNextRender;
    private int? trackedChannelId;
    private int? trackedLastMessageId;

    private int GetReplyCount(int messageId)
        => ThreadReplyCounts.TryGetValue(messageId, out var count) ? count : 0;

    protected override void OnParametersSet()
    {
        var currentChannelId = Messages.FirstOrDefault()?.ChannelId;
        var currentLastId = Messages.LastOrDefault()?.Id;

        if (currentChannelId != trackedChannelId)
        {
            // Channel switched — scroll to bottom for the new channel.
            scrollToBottomOnNextRender = true;
            trackedChannelId = currentChannelId;
        }
        else if (currentLastId != trackedLastMessageId && trackedLastMessageId != null && !IsLoadingMore)
        {
            // A new message was appended — scroll to bottom.
            scrollToBottomOnNextRender = true;
        }

        trackedLastMessageId = currentLastId;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            jsModule = await JS.InvokeAsync<IJSObjectReference>("import", "./js/chat.js");
            dotNetRef = DotNetObjectReference.Create(this);
            await jsModule.InvokeVoidAsync("observeScrollTop", "messageList", dotNetRef, topSentinel);
            scrollToBottomOnNextRender = true;
        }

        if (scrollToBottomOnNextRender && jsModule != null)
        {
            scrollToBottomOnNextRender = false;
            await jsModule.InvokeVoidAsync("scrollToBottom", scrollContainer);
        }
    }

    /// <summary>Allows the parent to imperatively scroll to the bottom.</summary>
    public async Task ScrollToBottomAsync()
    {
        if (jsModule != null)
            await jsModule.InvokeVoidAsync("scrollToBottom", scrollContainer);
    }

    [JSInvokable]
    public async Task OnScrolledToTop()
    {
        if (!IsLoadingMore)
            await OnLoadMore.InvokeAsync();
    }

    public async ValueTask DisposeAsync()
    {
        if (jsModule != null)
        {
            try
            {
                await jsModule.InvokeVoidAsync("dispose", "messageList");
                await jsModule.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }
        dotNetRef?.Dispose();
    }
}

