@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@using sv_e6277786bb234e2e88355c629b29b05f.Services
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>
<HeadContent>
    <link href="css/chat.css" rel="stylesheet" />
</HeadContent>

<div class="chat-container">
    <ChannelSidebar Channels="channels"
                    SelectedChannelId="selectedChannelId"
                    OnChannelSelected="SelectChannel" />

    <div class="main-area">
        @if (selectedChannel is not null)
        {
            <div class="channel-header">
                <h3># @selectedChannel.Name</h3>
                <p>@selectedChannel.Description</p>
            </div>

            <MessageList @ref="messageList"
                         Messages="messages"
                         ThreadReplyCounts="threadReplyCounts"
                         IsLoadingMore="isLoadingMore"
                         OnLoadMore="LoadMoreMessages"
                         OnOpenThread="OpenThread"
                         OnReact="AddReaction" />

            <MessageInput Placeholder="@($"Message #{selectedChannel.Name}")"
                          ButtonText="Send"
                          OnSubmit="SendMessage" />
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (threadRootMessage is not null)
    {
        <ThreadPanel RootMessage="threadRootMessage"
                     Replies="threadMessages"
                     OnClose="CloseThread"
                     OnSendReply="SendReply" />
    }
</div>

@code {
    private List<Channel> channels = new();
    private int? selectedChannelId;
    private Channel? selectedChannel;
    private List<Message> messages = new();
    private Dictionary<int, int> threadReplyCounts = new();
    private Message? threadRootMessage;
    private List<Message> threadMessages = new();
    private int messageSkip;
    private const int PageSize = 30;
    private bool isLoadingMore;
    private MessageList? messageList;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
            await SelectChannel(channels[0].Id);
    }

    private async Task SelectChannel(int channelId)
    {
        selectedChannelId = channelId;
        selectedChannel = channels.FirstOrDefault(c => c.Id == channelId);
        threadRootMessage = null;
        threadMessages.Clear();

        messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        messageSkip = messages.Count;

        await LoadThreadReplyCounts(messages);

        await ChatService.MarkChannelReadAsync(channelId);
        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
            channels[idx] = channels[idx] with { UnreadCount = 0 };
    }

    private async Task LoadMoreMessages()
    {
        if (isLoadingMore || selectedChannelId is null) return;

        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(selectedChannelId.Value, messageSkip, PageSize);
        if (older.Count > 0)
        {
            messages.InsertRange(0, older);
            messageSkip += older.Count;
            await LoadThreadReplyCounts(older);
        }

        isLoadingMore = false;
    }

    private async Task LoadThreadReplyCounts(List<Message> msgs)
    {
        foreach (var msg in msgs)
        {
            var replies = await ChatService.GetThreadAsync(msg.Id);
            if (replies.Count > 0)
                threadReplyCounts[msg.Id] = replies.Count;
        }
    }

    private async Task SendMessage(string content)
    {
        if (selectedChannelId is null) return;
        var msg = await ChatService.SendMessageAsync(selectedChannelId.Value, content, null);
        messages.Add(msg);
    }

    private async Task OpenThread(int rootMessageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (threadRootMessage is null) return;

        threadMessages = await ChatService.GetThreadAsync(rootMessageId);
        threadReplyCounts[rootMessageId] = threadMessages.Count;
    }

    private void CloseThread()
    {
        threadRootMessage = null;
        threadMessages.Clear();
    }

    private async Task SendReply(string content)
    {
        if (threadRootMessage is null || selectedChannelId is null) return;
        var reply = await ChatService.SendMessageAsync(selectedChannelId.Value, content, threadRootMessage.Id);
        threadMessages.Add(reply);
        threadReplyCounts[threadRootMessage.Id] = threadMessages.Count;
    }

    private async Task AddReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        var msg = messages.FirstOrDefault(m => m.Id == args.MessageId);
        if (msg is null) return;

        var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == args.Emoji);
        if (existing is not null)
        {
            if (!existing.Users.Contains("You"))
                existing.Users.Add("You");
        }
        else
        {
            msg.Reactions.Add(new Reaction(args.Emoji, new List<string> { "You" }));
        }
    }
}

